BEGIN TRANSACTION;
CREATE TABLE "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "auth_user" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "first_name" varchar(150) NOT NULL);
CREATE TABLE "auth_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "clinical_documents" ("tenant_id" integer NOT NULL, "id" char(32) NOT NULL PRIMARY KEY, "title" varchar(255) NOT NULL, "file_path" varchar(500) NOT NULL, "file_type" varchar(50) NOT NULL, "file_size" bigint NOT NULL, "mime_type" varchar(100) NOT NULL, "is_encrypted" bool NOT NULL, "is_processed" bool NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "created_by_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "clinical_record_id" char(32) NOT NULL REFERENCES "clinical_records" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "clinical_records" ("tenant_id" integer NOT NULL, "id" char(32) NOT NULL PRIMARY KEY, "title" varchar(255) NOT NULL, "description" text NOT NULL, "record_type" varchar(100) NOT NULL, "status" varchar(50) NOT NULL, "priority" varchar(20) NOT NULL, "is_active" bool NOT NULL, "is_confidential" bool NOT NULL, "record_date" date NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "created_by_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE "imaging_studies" ("tenant_id" integer NOT NULL, "id" char(32) NOT NULL PRIMARY KEY, "study_type" varchar(100) NOT NULL, "modality" varchar(50) NOT NULL, "study_date" date NOT NULL, "study_description" text NOT NULL, "created_at" datetime NOT NULL, "clinical_record_id" char(32) NOT NULL REFERENCES "clinical_records" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "manual_reviews" ("tenant_id" integer NOT NULL, "id" char(32) NOT NULL PRIMARY KEY, "status" varchar(50) NOT NULL, "priority" varchar(20) NOT NULL, "assigned_at" datetime NOT NULL, "completed_at" datetime NULL, "notes" text NOT NULL, "clinical_record_id" char(32) NOT NULL REFERENCES "clinical_records" ("id") DEFERRABLE INITIALLY DEFERRED, "reviewer_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "record_relationships" ("tenant_id" integer NOT NULL, "id" char(32) NOT NULL PRIMARY KEY, "relationship_type" varchar(100) NOT NULL, "description" text NOT NULL, "created_at" datetime NOT NULL, "created_by_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "source_record_id" char(32) NOT NULL REFERENCES "clinical_records" ("id") DEFERRABLE INITIALLY DEFERRED, "target_record_id" char(32) NOT NULL REFERENCES "clinical_records" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "reviewer_profiles" ("tenant_id" integer NOT NULL, "id" char(32) NOT NULL PRIMARY KEY, "specialization" varchar(100) NOT NULL, "max_daily_reviews" integer NOT NULL, "is_active" bool NOT NULL, "created_at" datetime NOT NULL, "user_id" integer NOT NULL UNIQUE REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "share_tokens" ("tenant_id" integer NOT NULL, "id" char(32) NOT NULL PRIMARY KEY, "token" varchar(255) NOT NULL UNIQUE, "expires_at" datetime NOT NULL, "is_active" bool NOT NULL, "access_count" integer NOT NULL, "created_at" datetime NOT NULL, "clinical_record_id" char(32) NOT NULL REFERENCES "clinical_records" ("id") DEFERRABLE INITIALLY DEFERRED, "created_by_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE UNIQUE INDEX "auth_group_permissions_group_id_permission_id_0cd325b0_uniq" ON "auth_group_permissions" ("group_id", "permission_id");
CREATE INDEX "auth_group_permissions_group_id_b120cbf9" ON "auth_group_permissions" ("group_id");
CREATE INDEX "auth_group_permissions_permission_id_84c5c92e" ON "auth_group_permissions" ("permission_id");
CREATE UNIQUE INDEX "auth_user_groups_user_id_group_id_94350c0c_uniq" ON "auth_user_groups" ("user_id", "group_id");
CREATE INDEX "auth_user_groups_user_id_6a12ed8b" ON "auth_user_groups" ("user_id");
CREATE INDEX "auth_user_groups_group_id_97559544" ON "auth_user_groups" ("group_id");
CREATE UNIQUE INDEX "auth_user_user_permissions_user_id_permission_id_14a6b632_uniq" ON "auth_user_user_permissions" ("user_id", "permission_id");
CREATE INDEX "auth_user_user_permissions_user_id_a95ead1b" ON "auth_user_user_permissions" ("user_id");
CREATE INDEX "auth_user_user_permissions_permission_id_1fbb5f2c" ON "auth_user_user_permissions" ("permission_id");
CREATE INDEX "django_admin_log_content_type_id_c4bce8eb" ON "django_admin_log" ("content_type_id");
CREATE INDEX "django_admin_log_user_id_c564eba6" ON "django_admin_log" ("user_id");
CREATE UNIQUE INDEX "django_content_type_app_label_model_76bd3d3b_uniq" ON "django_content_type" ("app_label", "model");
CREATE UNIQUE INDEX "auth_permission_content_type_id_codename_01ab375a_uniq" ON "auth_permission" ("content_type_id", "codename");
CREATE INDEX "auth_permission_content_type_id_2f476e4b" ON "auth_permission" ("content_type_id");
CREATE INDEX "clinical_records_created_by_id_a746ea5a" ON "clinical_records" ("created_by_id");
CREATE INDEX "clinical_documents_created_by_id_35d9b668" ON "clinical_documents" ("created_by_id");
CREATE INDEX "clinical_documents_clinical_record_id_cdc028de" ON "clinical_documents" ("clinical_record_id");
CREATE INDEX "imaging_studies_clinical_record_id_5800336c" ON "imaging_studies" ("clinical_record_id");
CREATE INDEX "manual_reviews_clinical_record_id_e26c4942" ON "manual_reviews" ("clinical_record_id");
CREATE INDEX "manual_reviews_reviewer_id_368d6938" ON "manual_reviews" ("reviewer_id");
CREATE INDEX "record_relationships_created_by_id_723da658" ON "record_relationships" ("created_by_id");
CREATE INDEX "record_relationships_source_record_id_3333441b" ON "record_relationships" ("source_record_id");
CREATE INDEX "record_relationships_target_record_id_28671fa8" ON "record_relationships" ("target_record_id");
CREATE INDEX "share_tokens_clinical_record_id_b26a03eb" ON "share_tokens" ("clinical_record_id");
CREATE INDEX "share_tokens_created_by_id_c67a7f42" ON "share_tokens" ("created_by_id");
CREATE INDEX "django_session_expire_date_a5c62663" ON "django_session" ("expire_date");
DELETE FROM "sqlite_sequence";
COMMIT;
